{
  "narrative": "你离开青茂后，旧识和附近目击者议论纷纷。有人觉得你冒险出走是勇敢之举，但也流传着你不顾后果的谣言。一位曾共事的药师托人带话，希望私下见你，但需小心被眼线盯上。",
  "social_pressure": [
    "青茂坊间出现两种声音：赞你果断或斥你鲁莽。",
    "有匿名纸条警告你最近别露面，说有人打听你下落。"
  ],
  "npc_contact_windows": [
    "前同事老周托人传话，约你三日后在城西茶馆见面。"
  ],
  "faction_preconditions": [
    "需确认老周是否被其他势力监控。",
    "最好先通过中间人传递消息，避免直接现身。"
  ],
  "safe_next_steps": [
    "先让可靠朋友去茶馆探风。",
    "准备一套换装和临时身份。"
  ],
  "safety_notes": [
    "青茂城门附近有陌生探子徘徊。",
    "你常用的落脚点可能已被盯梢。"
  ]
}

{
  "narrative": "你询问前同学是否已准备好提供资源，但公开信息中没有任何确凿的信任证据。坊间传言他可能对你持观望态度，也有人警告说他的立场并不明朗，直接求助可能导致行踪暴露。",
  "social_pressure": [
    "有人劝你别轻信旧识，称其可能被迫配合调查",
    "部分消息暗示他私下仍愿帮忙，但需极其谨慎"
  ],
  "npc_contact_windows": [
    "可通过共同好友捎话试探其真实态度"
  ],
  "faction_preconditions": [
    "需确认该同学最近是否被其他势力接触或监视",
    "最好先通过中立第三方确认他当前处境"
  ],
  "safe_next_steps": [
    "委托一位可靠信使传递隐晦问题，观察反应后再决定是否见面"
  ],
  "safety_notes": [
    "不要期望任何正式资源或承诺，一切以传言和间接试探为准"
  ]
}

{
  "narrative": "你试图将旧日传闻与一段模糊记忆强行升格为确定的帮助，但公开层面只有谨慎的推测和零散线索。他本人并未给出任何承诺，反而有人提醒你他的立场可能已变。必须通过间接渠道核实当前处境，不能直接依赖。",
  "social_pressure": [
    "有人警告你，他可能已被其他势力接触，贸然求助风险极高",
    "少量声音坚持他仍念旧情，但需要你主动证明安全"
  ],
  "npc_contact_windows": [
    "通过共同朋友传递试探性消息",
    "在公开集会场合制造偶遇机会"
  ],
  "faction_preconditions": [
    "确认他近期是否与敌对势力有过接触",
    "先通过中立第三方了解他当前的真实处境"
  ],
  "safe_next_steps": [
    "委托可靠中间人打探风声，不暴露自身意图"
  ],
  "safety_notes": [
    "不要将传闻和记忆当作确定性证据，保持行动隐蔽"
  ]
}

{
  "narrative": "你通过商队中间人传话后，百家寨内部议论更盛。部分人认为你主动试探是诚意，另一部分则警觉这是探子行为。商队私下流传，你与青毛事件中的某件失踪物品有关联，但无人能证实。目前寨中长老仍未松口，但联络人老陈通过中间人回话：若想进一步，需先替寨子解决一件麻烦事——近期有批货物被官府扣押，若能探明扣押地点，便是投名状。",
  "social_pressure": [
    "寨内对你的动机存在分歧，接近你的人可能被怀疑",
    "商队中有人暗示你最好先证明自己不是官府的人",
    "有谣言称你私藏了青毛的遗物，可能引来官府追查"
  ],
  "npc_contact_windows": [
    "通过中间人可约老陈在镇外破庙见面，但需自带引荐信物",
    "若在集市遇到百家寨采购的寨丁，可借机搭话并提及中间人名字"
  ],
  "faction_preconditions": [
    "需先查明被扣货物的具体位置，作为投名状",
    "至少获得一名寨内正式成员的口头担保，才能安排与长老会面"
  ],
  "safe_next_steps": [
    "通过商队情报网络打探官府扣押货物的仓库位置"
  ],
  "safety_notes": [
    "不要直接承认与青毛事件有关联，避免被当作目标",
    "与百家寨接触时注意避开官府眼线"
  ]
}

